import sys

# Function to validate Docker image tags
if __name__ == '__main__':
    for tag in sys.stdin:
        print(validateTag(tag.strip()))
def validateTag(tag):
    if tag.startswith('<') and tag.endswith('>'): 
        parts = tag.split(':')
        if len(parts) > 2:
            return False
        return True
    return False
